function decode(bytes, key){

return java.createSymmetricCrypto(
	"aes/cbc/pkcs7padding", 
	 key,
	"0".repeat(16)
	)
.decrypt(bytes)

}

if (/enc.webp/.test(src)) {
  let key = src.match(/"key":"(.+?)"/)[1]
  decode(result, key)
} else {
   result
}

